// Package report renders gruff-go analysis results into output formats.
// This file embeds the CSS and JavaScript assets used by the dashboard shell.
package report

// dashboardCSS is the inline stylesheet served with the dashboard shell document.
const dashboardCSS = `:root{color-scheme:dark;--paper:#f3e9d2;--ink:#11100e;--panel:#1b1815;--field:#0d0c0a;--line:#332d27;--muted:#b5ab94;--accent:#e85d04;--accent-dark:#120f0d}*{box-sizing:border-box}body{margin:0;background:var(--ink);color:var(--paper);font:14px ui-monospace,SFMono-Regular,Menlo,Monaco,Consolas,monospace;height:100vh;overflow:hidden}.controls-toggle{position:fixed;top:14px;right:24px;z-index:20;width:44px;height:44px;border:1px solid var(--accent);border-radius:6px;background:var(--accent);color:var(--accent-dark);font:700 24px/1 ui-monospace,SFMono-Regular,Menlo,Monaco,Consolas,monospace;cursor:pointer;display:grid;place-items:center;box-shadow:0 4px 14px rgba(0,0,0,.45)}.controls-toggle.busy:after{content:'';position:absolute;right:5px;bottom:5px;width:9px;height:9px;border-radius:50%;background:var(--paper);border:1px solid var(--accent-dark)}.controls-panel{position:fixed;top:66px;right:24px;z-index:21;width:min(560px,calc(100vw - 48px));max-height:calc(100vh - 86px);overflow:auto;background:var(--panel);border:1px solid var(--line);border-radius:8px;box-shadow:0 18px 50px rgba(0,0,0,.45);padding:18px}.panel-head{display:flex;align-items:flex-start;justify-content:space-between;gap:18px;padding-bottom:14px;border-bottom:1px solid var(--line)}.panel-head strong{display:block;font:italic 30px Georgia,Iowan Old Style,serif;letter-spacing:0}.panel-head span{display:block;margin-top:4px;color:var(--muted);font-size:10px;text-transform:uppercase;letter-spacing:.18em}.panel-head button{width:44px;height:44px;padding:0;border:1px solid var(--line);background:var(--field);color:var(--paper);font-size:24px;line-height:1}.scan-summary{display:grid;grid-template-columns:minmax(108px,auto) 1fr;gap:10px 18px;margin:18px 0 16px;padding:14px 16px;background:var(--field);border:1px solid var(--line);font-size:12px}.scan-status,.scan-command{display:contents}.scan-summary span{color:var(--muted);text-transform:uppercase;letter-spacing:.12em}.scan-summary strong,.scan-summary code{min-width:0;color:var(--paper);font:13px ui-monospace,SFMono-Regular,Menlo,Monaco,Consolas,monospace}.scan-meta-line{min-width:0;display:grid;grid-template-columns:1fr auto;gap:10px;align-items:start}.scan-summary code{white-space:normal;overflow:visible;overflow-wrap:anywhere;word-break:break-word}.scan-meta-line button{align-self:start;min-width:68px;padding:7px 9px;font-size:11px}form{display:grid;grid-template-columns:1fr;gap:14px}.field-stack,.field-grid,.option-grid{display:grid;gap:12px}.field-grid{grid-template-columns:1fr 1fr}.option-grid{grid-template-columns:repeat(4,minmax(0,1fr));padding:4px 0}label{display:flex;flex-direction:column;gap:7px;color:var(--muted);font-size:11px;text-transform:uppercase;letter-spacing:.1em}.check{display:grid;grid-template-columns:auto 1fr;align-items:center;gap:10px;text-transform:none;letter-spacing:0;font-size:12px;color:var(--paper);line-height:1.35}.check span{min-width:0}input,select{width:100%;min-height:46px;border:1px solid var(--line);background:var(--field);color:var(--paper);padding:10px 12px;font:14px ui-monospace,SFMono-Regular,Menlo,Monaco,Consolas,monospace}input[type=checkbox]{width:18px;min-height:18px;height:18px;margin:0;accent-color:var(--accent)}button{border:1px solid var(--accent);background:var(--accent);color:var(--accent-dark);padding:12px 14px;font:700 13px ui-monospace,SFMono-Regular,Menlo,Monaco,Consolas,monospace;cursor:pointer}button:focus-visible,input:focus-visible,select:focus-visible{outline:2px solid var(--paper);outline-offset:2px}button:disabled{opacity:.6;cursor:wait}.panel-actions{display:grid;grid-template-columns:1fr 1fr;gap:12px;padding-top:2px}.panel-actions button{min-height:48px}iframe{width:100vw;height:100vh;border:0;background:var(--field);display:block}@media(max-width:700px){.controls-toggle{top:10px;right:18px}.controls-panel{top:60px;right:18px;width:calc(100vw - 36px);padding:16px}.field-grid,.option-grid,.scan-summary,.scan-meta-line{grid-template-columns:1fr}.panel-head strong{font-size:28px}}`

// dashboardJS is the inline script that wires up the dashboard form to the report iframe.
const dashboardJS = `const form=document.getElementById('scan-form');const frame=document.getElementById('report-frame');const refresh=document.getElementById('refresh');const runButton=document.getElementById('run-scan');const status=document.getElementById('scan-status');const scanMeta=document.getElementById('scan-meta');const copyScanMeta=document.getElementById('copy-scan-meta');const toggle=document.getElementById('controls-toggle');const panel=document.getElementById('controls-panel');const close=document.getElementById('controls-close');let scans=0;let busyTimer=null;let busyStarted=0;function params(){return new URLSearchParams(new FormData(form));}function setOpen(open){panel.hidden=!open;toggle.setAttribute('aria-expanded',open?'true':'false');if(open){form.elements.project.focus();}}function stopBusyTimer(){if(busyTimer!==null){clearInterval(busyTimer);busyTimer=null;}}function renderBusy(){status.textContent='Scanning... '+Math.floor((Date.now()-busyStarted)/1000)+'s';}function setBusy(busy){refresh.disabled=busy;runButton.disabled=busy;toggle.classList.toggle('busy',busy);toggle.setAttribute('aria-label',busy?'Scanning':'Dashboard controls');stopBusyTimer();if(busy){busyStarted=Date.now();renderBusy();busyTimer=setInterval(renderBusy,1000);}else{status.textContent='Scan loaded';}}function updateMeta(data){if(!data||data.type!=='gruff-scan-complete'){return;}const exit=Number.isInteger(data.exitCode)?data.exitCode:'?';const duration=Number.isInteger(data.durationMs)?data.durationMs+'ms':'duration n/a';const command=typeof data.command==='string'?data.command:'';scanMeta.textContent='exit '+exit+' · '+duration+(command===''?'':' · '+command);}async function copyMeta(){const text=scanMeta.textContent||'';try{if(navigator.clipboard&&window.isSecureContext){await navigator.clipboard.writeText(text);}else{const range=document.createRange();range.selectNodeContents(scanMeta);const selection=window.getSelection();if(selection){selection.removeAllRanges();selection.addRange(range);document.execCommand('copy');selection.removeAllRanges();}}copyScanMeta.textContent='Copied';setTimeout(()=>{copyScanMeta.textContent='Copy';},1200);}catch(error){copyScanMeta.textContent='Copy failed';setTimeout(()=>{copyScanMeta.textContent='Copy';},1200);}}function run(){const qs=params();const visible=new URLSearchParams(qs);qs.set('_run',Date.now().toString()+'-'+(++scans));setBusy(true);frame.removeAttribute('srcdoc');frame.src='/scan?'+qs.toString();history.replaceState(null,'','/?'+visible.toString());}toggle.addEventListener('click',event=>{event.stopPropagation();setOpen(panel.hidden);});close.addEventListener('click',()=>setOpen(false));document.addEventListener('click',event=>{if(!panel.hidden&&!panel.contains(event.target)&&event.target!==toggle){setOpen(false);}});document.addEventListener('keydown',event=>{if(event.key==='Escape'){setOpen(false);}});window.addEventListener('message',event=>{if(event.origin!==window.location.origin)return;updateMeta(event.data);});frame.addEventListener('load',()=>{setBusy(false);try{const el=frame.contentDocument&&frame.contentDocument.getElementById('gruff-dashboard-meta');if(el){updateMeta(JSON.parse(el.textContent||'{}'));}}catch(error){}});form.addEventListener('submit',event=>{event.preventDefault();run();});refresh.addEventListener('click',run);copyScanMeta.addEventListener('click',copyMeta);setTimeout(run,0);`
